const fs = require('fs');
const path = require('path');

const COMPANY_SCOPE = '@company';
const PRIVATE_REGISTRY = 'https://npm.company.internal';

const packageJson = JSON.parse(fs.readFileSync(path.join(process.cwd(), 'package.json'), 'utf8'));

const internalPackages = Object.keys({
  ...packageJson.dependencies,
  ...packageJson.devDependencies
}).filter(pkg => pkg.startsWith(COMPANY_SCOPE));

console.log('Validating internal package dependencies...');

internalPackages.forEach(pkg => {
  console.log(`  ✓ ${pkg} (internal)`);
});

const npmrcPath = path.join(process.cwd(), '.npmrc');
if (!fs.existsSync(npmrcPath)) {
  console.error('ERROR: .npmrc file not found. Creating default configuration...');
  const npmrcContent = `${COMPANY_SCOPE}:registry=${PRIVATE_REGISTRY}
registry=https://registry.npmjs.org/
always-auth=true
//npm.company.internal/:_authToken=\${NPM_TOKEN}`;
  fs.writeFileSync(npmrcPath, npmrcContent);
}

const npmrcContent = fs.readFileSync(npmrcPath, 'utf8');
if (!npmrcContent.includes(COMPANY_SCOPE) || !npmrcContent.includes(PRIVATE_REGISTRY)) {
  console.error(`ERROR: .npmrc must configure ${COMPANY_SCOPE} scope to use ${PRIVATE_REGISTRY}`);
  process.exit(1);
}

console.log('Dependency validation complete.');